import{_ as t,o as r,c as d,ag as o}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse(`{"title":"Alias Chmod : raccourcis de permissions pour le shell | Dotfiles (FR)","titleTemplate":":title","description":"Simplifiez la gestion des permissions avec des alias chmod. Raccourcis pour les motifs courants comme 755, 644, etc.","frontmatter":{"title":"Alias Chmod : raccourcis de permissions pour le shell","description":"Simplifiez la gestion des permissions avec des alias chmod. Raccourcis pour les motifs courants comme 755, 644, etc.","lang":"fr-FR","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Chmod : raccourcis de permissions pour le shell preview","canonical":"/fr/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Chmod : raccourcis de permissions pour le shell","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Chmod | Dotfiles","permalink":"/fr/aliases/chmod/","sidebar":true,"meta":[{"name":"keywords","content":"alias chmod, permissions fichiers, raccourcis shell, dotfiles, permissions unix"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Alias Chmod | Dotfiles"},{"name":"twitter:description","content":"Simplifiez la gestion des permissions avec des alias chmod."},{"name":"og:title","content":"Alias Chmod | Dotfiles"},{"name":"og:description","content":"Simplifiez la gestion des permissions avec des alias chmod."},{"name":"og:image:alt","content":"Dotfiles - Conçus pour s'adapter à votre vie de shell"},{"name":"og:locale","content":"fr_FR"}]},"headers":[],"relativePath":"fr/aliases/chmod/index.md","filePath":"fr/aliases/chmod/index.md","lastUpdated":1773010926000}`),i={name:"fr/aliases/chmod/index.md"};function s(a,e,c,l,n,u){return r(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="alias-chmod" tabindex="-1">Alias Chmod <a class="header-anchor" href="#alias-chmod" aria-label="Permalink to &quot;Alias Chmod&quot;">​</a></h1><p>Raccourcis pour gérer les permissions des fichiers et répertoires.</p><p><img src="https://kura.pro/dotfiles/v2/images/titles/title-dotfiles.svg" alt="Dotfiles banner"></p><h2 id="apercu" tabindex="-1">Aperçu <a class="header-anchor" href="#apercu" aria-label="Permalink to &quot;Aperçu&quot;">​</a></h2><p>Les alias chmod offrent un moyen rapide de gérer les permissions depuis la ligne de commande. Au lieu de mémoriser les codes numériques, utilisez des alias intuitifs comme <code>chmod_755</code> ou <code>chmod_u+x</code> pour définir l’accès souhaité.</p><p>Ces alias sont définis dans <code>chmod.aliases.sh</code> et chargés automatiquement par chezmoi.</p><h2 id="reference" tabindex="-1">Référence <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Référence&quot;">​</a></h2><h3 id="alias-de-permissions-courantes" tabindex="-1">Alias de permissions courantes <a class="header-anchor" href="#alias-de-permissions-courantes" aria-label="Permalink to &quot;Alias de permissions courantes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Permissions</th><th>Description</th></tr></thead><tbody><tr><td><code>chmod_000</code></td><td><code>----------</code></td><td>Aucune permission pour tous</td></tr><tr><td><code>chmod_400</code></td><td><code>r--------</code></td><td>Lecture seule pour le propriétaire</td></tr><tr><td><code>chmod_444</code></td><td><code>r--r--r--</code></td><td>Lecture seule pour tous</td></tr><tr><td><code>chmod_600</code></td><td><code>rw-------</code></td><td>Lecture/écriture pour le propriétaire</td></tr><tr><td><code>chmod_644</code></td><td><code>rw-r--r--</code></td><td>Lecture/écriture pour le propriétaire, lecture seule pour les autres</td></tr><tr><td><code>chmod_666</code></td><td><code>rw-rw-rw-</code></td><td>Lecture/écriture pour tous</td></tr><tr><td><code>chmod_755</code></td><td><code>rwxr-xr-x</code></td><td>Plein accès propriétaire, lecture/exécution pour les autres</td></tr><tr><td><code>chmod_764</code></td><td><code>rwxrw-r--</code></td><td>Plein accès propriétaire, lecture/écriture pour le groupe</td></tr><tr><td><code>chmod_777</code></td><td><code>rwxrwxrwx</code></td><td>Pleines permissions pour tous</td></tr></tbody></table><h3 id="alias-de-permissions-du-proprietaire" tabindex="-1">Alias de permissions du propriétaire <a class="header-anchor" href="#alias-de-permissions-du-proprietaire" aria-label="Permalink to &quot;Alias de permissions du propriétaire&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Description</th></tr></thead><tbody><tr><td><code>chmod_u+x</code></td><td>Ajouter l’exécution pour le propriétaire</td></tr><tr><td><code>chmod_u-x</code></td><td>Retirer l’exécution pour le propriétaire</td></tr><tr><td><code>chmod_u+w</code></td><td>Ajouter l’écriture pour le propriétaire</td></tr><tr><td><code>chmod_u-w</code></td><td>Retirer l’écriture pour le propriétaire</td></tr><tr><td><code>chmod_u+r</code></td><td>Ajouter la lecture pour le propriétaire</td></tr><tr><td><code>chmod_u-r</code></td><td>Retirer la lecture pour le propriétaire</td></tr></tbody></table><h3 id="alias-de-permissions-du-groupe" tabindex="-1">Alias de permissions du groupe <a class="header-anchor" href="#alias-de-permissions-du-groupe" aria-label="Permalink to &quot;Alias de permissions du groupe&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Description</th></tr></thead><tbody><tr><td><code>chmod_g+x</code></td><td>Ajouter l’exécution pour le groupe</td></tr><tr><td><code>chmod_g-x</code></td><td>Retirer l’exécution pour le groupe</td></tr><tr><td><code>chmod_g+w</code></td><td>Ajouter l’écriture pour le groupe</td></tr><tr><td><code>chmod_g-w</code></td><td>Retirer l’écriture pour le groupe</td></tr><tr><td><code>chmod_g+r</code></td><td>Ajouter la lecture pour le groupe</td></tr><tr><td><code>chmod_g-r</code></td><td>Retirer la lecture pour le groupe</td></tr></tbody></table><h3 id="alias-de-permissions-des-autres" tabindex="-1">Alias de permissions des autres <a class="header-anchor" href="#alias-de-permissions-des-autres" aria-label="Permalink to &quot;Alias de permissions des autres&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Description</th></tr></thead><tbody><tr><td><code>chmod_o+x</code></td><td>Ajouter l’exécution pour les autres</td></tr><tr><td><code>chmod_o-x</code></td><td>Retirer l’exécution pour les autres</td></tr><tr><td><code>chmod_o+w</code></td><td>Ajouter l’écriture pour les autres</td></tr><tr><td><code>chmod_o-w</code></td><td>Retirer l’écriture pour les autres</td></tr><tr><td><code>chmod_o+r</code></td><td>Ajouter la lecture pour les autres</td></tr><tr><td><code>chmod_o-r</code></td><td>Retirer la lecture pour les autres</td></tr></tbody></table><h3 id="alias-par-type-de-fichier" tabindex="-1">Alias par type de fichier <a class="header-anchor" href="#alias-par-type-de-fichier" aria-label="Permalink to &quot;Alias par type de fichier&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Description</th></tr></thead><tbody><tr><td><code>chmod_755d</code></td><td>Définir les permissions des dossiers sur <code>rwxr-xr-x</code></td></tr><tr><td><code>chmod_644f</code></td><td>Définir les permissions des fichiers sur <code>rw-r--r--</code></td></tr></tbody></table><h3 id="fonction-recursive" tabindex="-1">Fonction récursive <a class="header-anchor" href="#fonction-recursive" aria-label="Permalink to &quot;Fonction récursive&quot;">​</a></h3><p>La fonction <code>change_permission</code> applique les permissions récursivement avec confirmation :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">change_permission</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/directory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span></span></code></pre></div>',20)])])}const m=t(i,[["render",s]]);export{h as __pageData,m as default};
